     2→// SPDX-License-Identifier: MIT
     3→pragma solidity ^0.8.20;
     4→
     5→/**
     6→ * @title ShowPass
     7→ * @notice Upgradeable ERC-721 NFT that functions as an interactive ticket for
     8→ *         StellarStage Carnival shows.  The pass levels-up with on-chain
     9→ *         experience, can be staked for governance, and respects creator
    10→ *         royalties (ERC-2981).  The contract is secured behind access-roles
    11→ *         and can be upgraded through the UUPS proxy pattern.
    12→ *
    13→ * Clean-Architecture Considerations
    14→ * ---------------------------------
    15→ * • Domain logic (leveling, staking, governance weight) is contained in this
    16→ *   contract—the “core” layer—while higher-level orchestration lives in
    17→ *   TypeScript services (MintShowPass, StakePass, CastLiveVote, …).
    18→ * • External dependencies are abstracted behind interfaces (e.g. IXPSource)
    19→ *   to keep the contract testable and chain-agnostic.
    20→ */
    21→
    22→import {ERC721EnumerableUpgradeable}     from "@openzeppelin/contracts-upgradeable/token/ERC721/extensions/ERC721EnumerableUpgradeable.sol";
    23→import {AccessControlUpgradeable}        from "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
    24→import {PausableUpgradeable}             from "@openzeppelin/contracts-upgradeable/security/PausableUpgradeable.sol";
    25→import {ReentrancyGuardUpgradeable}      from "@openzeppelin/contracts-upgradeable/security/ReentrancyGuardUpgradeable.sol";
    26→import {UUPSUpgradeable}                 from "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
    27→import {ERC2981Upgradeable}              from "@openzeppelin/contracts-upgradeable/token/common/ERC2981Upgradeable.sol";
    28→import {Counters}                        from "@openzeppelin/contracts/utils/Counters.sol";
    29→
    30→/// -----------------------------------------------------------------------
    31→/// Custom errors (cheaper than revert strings)
    32→/// -----------------------------------------------------------------------
    33→error Unauthorized();
    34→error InvalidToken();
    35→error AlreadyStaked();
    36→error NotStaked();
    37→error ZeroAddress();
    38→
    39→contract ShowPass is
    40→    ERC721EnumerableUpgradeable,
    41→    ERC2981Upgradeable,
    42→    AccessControlUpgradeable,
    43→    PausableUpgradeable,
    44→    ReentrancyGuardUpgradeable,
    45→    UUPSUpgradeable
    46→{
    47→    using Counters for Counters.Counter;
    48→
    49→    /// -------------------------------------------------------------------
    50→    /// Roles
    51→    /// -------------------------------------------------------------------
    52→    bytes32 public constant ADMIN_ROLE   = keccak256("ADMIN_ROLE");
    53→    bytes32 public constant MINTER_ROLE  = keccak256("MINTER_ROLE");
    54→    bytes32 public constant STAGE_ROLE   = keccak256("STAGE_ROLE"); // show runtime data feeder
    55→
    56→    /// -------------------------------------------------------------------
    57→    /// Pass domain model
    58→    /// -------------------------------------------------------------------
    59→    struct PassData {
    60→        uint8   level;          // Player level (1-255)
    61→        uint32  xp;             // Accumulated experience
    62→        bool    staked;         // Is pass currently staked for governance?
    63→        uint64  stakeTimestamp; // When staking started (unix time)
    64→    }
    65→
    66→    Counters.Counter private _tokenIds;                 // incremental id counter
    67→    mapping(uint256 => PassData) internal _passData;    // tokenId => data
    68→
    69→    string private _baseTokenURI;                       // metadata root
    70→    uint32 private constant _XP_PER_LEVEL = 1_000 ether /* scaled */;
    71→
    72→    /// -------------------------------------------------------------------
    73→    /// Events
    74→    /// -------------------------------------------------------------------
    75→    event PassMinted(address indexed to, uint256 indexed tokenId);
    76→    event LevelUp(uint256 indexed tokenId, uint8 newLevel);
    77→    event PassStaked(uint256 indexed tokenId);
    78→    event PassUnstaked(uint256 indexed tokenId, uint64 durationSec);
    79→
    80→    /// -------------------------------------------------------------------
    81→    /// Initializer (replaces constructor for proxy pattern)
    82→    /// -------------------------------------------------------------------
    83→    function initialize(
    84→        string memory name_,
    85→        string memory symbol_,
    86→        string memory baseURI_,
    87→        address defaultRoyaltyReceiver,
    88→        uint96  defaultRoyaltyFeeNumerator /* in bps */
    89→    ) external initializer {
    90→        if (defaultRoyaltyReceiver == address(0)) revert ZeroAddress();
    91→
    92→        __ERC721_init(name_, symbol_);
    93→        __ERC721Enumerable_init();
    94→        __AccessControl_init();
    95→        __Pausable_init();
    96→        __ReentrancyGuard_init();
    97→        __UUPSUpgradeable_init();
    98→        __ERC2981_init();
    99→
   100→        _baseTokenURI = baseURI_;
   101→
   102→        // Role configuration
   103→        _grantRole(DEFAULT_ADMIN_ROLE, _msgSender());
   104→        _grantRole(ADMIN_ROLE,           _msgSender());
   105→        _grantRole(MINTER_ROLE,          _msgSender());
   106→        _grantRole(STAGE_ROLE,           _msgSender());
   107→
   108→        // Set default royalty (can be overridden per-token)
   109→        _setDefaultRoyalty(defaultRoyaltyReceiver, defaultRoyaltyFeeNumerator);
   110→    }
   111→
   112→    /// -------------------------------------------------------------------
   113→    /// Minting
   114→    /// -------------------------------------------------------------------
   115→
   116→    /**
   117→     * @notice Mint a new ShowPass to `to`
