     3→pragma solidity ^0.8.20;
     4→
     5→/**
     6→ * @title  ShowPassProxy
     7→ * @author StellarStage Carnival
     8→ * @notice Transparent upgradeable proxy that delegates calls to the current
     9→ *         ShowPass implementation. Inspired by OpenZeppelin’s ERC1967Proxy
    10→ *         but with a slimmed-down surface specifically tailored for the
    11→ *         dynamic, on-chain “Show Pass” NFT contract.
    12→ *
    13→ *         The proxy guarantees:
    14→ *           • Storage separation between proxy and implementation
    15→ *           • Creator-royalty immutability (hard-coded in proxy storage)
    16→ *           • Upgrade governance via a 2-step timelock handshake
    17→ *           • EIP-1967 compliant storage slots for tooling support
    18→ *
    19→ * @dev    Administration flow
    20→ *         1. `proxyAdmin` queues an upgrade by calling `proposeUpgrade`.
    21→ *         2. After the mandatory timelock, `proxyAdmin` finalises the
    22→ *            upgrade via `upgradeTo` (or `upgradeToAndCall` for init data).
    23→ *
    24→ *         SECURITY: Never interact with the proxy admin address through a
    25→ *         dApp. User-facing calls MUST be sent to the proxy address directly,
    26→ *         allowing the proxy to forward them to the implementation.
    27→ */
    28→contract ShowPassProxy {
    29→    /* --------------------------------------------------------------------- */
    30→    /*                                LIBRARIES                              */
    31→    /* --------------------------------------------------------------------- */
    32→    using Address for address;
    33→
    34→    /* --------------------------------------------------------------------- */
    35→    /*                              CONSTANTS                                */
    36→    /* --------------------------------------------------------------------- */
    37→
    38→    // keccak256("eip1967.proxy.admin") − 1
    39→    bytes32 private constant _ADMIN_SLOT =
    40→        0xb53127684a568b3173ae13b9f8a6016e019ccc0d1d41b79e4b938e3c7e40d0ed;
    41→
    42→    // keccak256("eip1967.proxy.implementation") − 1
    43→    bytes32 private constant _IMPLEMENTATION_SLOT =
    44→        0x360894a13ba1a3210667c828492db98dca3e2076cc3735a920a3ca505d382bbc;
    45→
    46→    // keccak256("stellars.stage.proxy.upgradeProposal") − 1
    47→    bytes32 private constant _UPGRADE_PROPOSAL_SLOT =
    48→        0xb99fb3f26f9d45098f2d69a54164a1c456d24c46178cf66b20ef7b814e48d630;
    49→
    50→    // keccak256("stellars.stage.proxy.timelockExpiration") − 1
    51→    bytes32 private constant _TIMELOCK_SLOT =
    52→        0xb7c295bb4e62a8d76da9e9e9855c3d53295d85f1e4b74e6a1afd37d399a8ce46;
    53→
    54→    // Default mandatory delay before an upgrade can be executed (48h)
    55→    uint256 public constant MIN_TIMELOCK = 48 hours;
    56→
    57→    /* --------------------------------------------------------------------- */
    58→    /*                                 EVENTS                                */
    59→    /* --------------------------------------------------------------------- */
    60→
    61→    event UpgradeProposed(address indexed proposer, address implementation, uint256 executeAfter);
    62→    event Upgraded(address indexed admin, address indexed implementation);
    63→    event AdminChanged(address indexed previousAdmin, address indexed newAdmin);
    64→
    65→    /* --------------------------------------------------------------------- */
    66→    /*                              CONSTRUCTOR                              */
    67→    /* --------------------------------------------------------------------- */
    68→
    69→    /**
    70→     * @param _logic        Initial implementation address.
    71→     * @param _admin        Address with power to manage upgrades.
    72→     * @param _initData     Optional data for the implementation’s initializer.
    73→     *
    74→     * NOTE: The constructor is executed only once at deployment and will never
    75→     *       be part of the delegate-called logic, hence does not need to be
    76→     *       upgrade-safe.
    77→     */
    78→    constructor(address _logic, address _admin, bytes memory _initData) payable {
    79→        require(_logic.isContract(), "ShowPassProxy: logic is not contract");
    80→        require(_admin != address(0), "ShowPassProxy: admin is zero");
    81→
    82→        _setAdmin(_admin);
    83→        _setImplementation(_logic);
    84→
    85→        if (_initData.length > 0) {
    86→            _functionDelegateCall(_logic, _initData);
    87→        }
    88→    }
    89→
    90→    /* --------------------------------------------------------------------- */
    91→    /*                             ADMIN GETTERS                             */
    92→    /* --------------------------------------------------------------------- */
    93→
    94→    function admin() public view returns (address adm) {
    95→        assembly {
    96→            adm := sload(_ADMIN_SLOT)
    97→        }
    98→    }
    99→
   100→    function implementation() public view returns (address impl) {
   101→        assembly {
   102→            impl := sload(_IMPLEMENTATION_SLOT)
   103→        }
   104→    }
   105→
   106→    /* --------------------------------------------------------------------- */
   107→    /*                         UPGRADE PROPOSAL FLOW                         */
   108→    /* --------------------------------------------------------------------- */
   109→
   110→    /**
   111→     * @notice Queues an implementation upgrade. Can be executed after the
   112→     *         timelock expires via `upgradeTo`.
   113→     * @param newImplementation Address of the new logic contract.
   114→     */
   115→    function proposeUpgrade(address newImplementation) external onlyAdmin {
   116→        require(newImplementation.isContract(), "Proxy: new impl not contract");
   117→        require(newImplementation != implementation(), "Proxy: same implementation");
   118→
   119→        _setUpgradeProposal(newImplementation);
   120→        uint256 executeAfter = block.timestamp + MIN_TIMELOCK;
   121→        _setTimelock(executeAfter);
   122→
   123→        emit UpgradeProposed(msg.sender, newImplementation, executeAfter);
   124→    }
   125→
   126→    /**
   127→     * @notice Executes a previously proposed upgrade once timelock expired.
   128→     * @param newImplementation Address of the new logic contract (must match
   129→     *                           the proposal).
   130→     */
   131→    function upgradeTo(address newImplementation) public onlyAdmin {
   132→        _checkTimelock(newImplementation);
   133→        _upgradeTo(newImplementation);
   134→    }
   135→
   136→    /**
   137→     * @notice Same as `upgradeTo` but also calls a function on the new
   138→     *         implementation (e.g. `initializeV2`).
   139→     */
   140→    function upgradeToAndCall(address newImplementation, bytes calldata data) external payable onlyAdmin {
   141→        _checkTimelock(newImplementation);
   142→        _upgradeTo(newImplementation);
   143→
   144→        if (data.length > 0) {
   145→            _functionDelegateCall(newImplementation, data);
   146→        }
   147→    }
   148→
   149→    /* --------------------------------------------------------------------- */
   150→    /*                        ADMIN MAINTENANCE UTILITIES                    */
   151→    /* --------------------------------------------------------------------- */
   152→
   153→    /**
   154→     * @notice Transfers proxy admin rights.
   155→     */
   156→    function changeAdmin(address newAdmin) external onlyAdmin {
   157→        require(newAdmin != address(0), "Proxy: new admin zero");
