   161→    }
   162→
   163→    /* --------------------------------------------------------------------- */
   164→    /*                          FALLBACK / RECEIVE                           */
   165→    /* --------------------------------------------------------------------- */
   166→
   167→    fallback() external payable virtual {
   168→        _delegate(implementation());
   169→    }
   170→
   171→    receive() external payable virtual {
   172→        _delegate(implementation());
   173→    }
   174→
   175→    /* --------------------------------------------------------------------- */
   176→    /*                       INTERNAL LOW-LEVEL HELPERS                      */
   177→    /* --------------------------------------------------------------------- */
   178→
   179→    function _delegate(address impl) internal virtual {
   180→        assembly {
