   193→                case 0 {
   194→                    // Delegatecall failed.
   195→                    revert(0, returndatasize())
   196→                }
   197→                default {
   198→                    // Delegatecall succeeded.
   199→                    return(0, returndatasize())
   200→                }
   201→        }
   202→    }
   203→
   204→    function _upgradeTo(address newImplementation) internal {
   205→        _setImplementation(newImplementation);
   206→        // Reset proposal/timelock
   207→        _setUpgradeProposal(address(0));
   208→        _setTimelock(0);
   209→
   210→        emit Upgraded(msg.sender, newImplementation);
   211→    }
   212→
   213→    /* --------------------------------------------------------------------- */
   214→    /*                             STORAGE SETTERS                           */
   215→    /* --------------------------------------------------------------------- */
   216→
