     2→/******************************************************************************************
     3→ * StellarStage Carnival – Ethers infrastructure adapter
     4→ *
     5→ * This module provides a thin but production-ready wrapper around ethers.js that is used
     6→ * by application-level use-cases (MintShowPass, StakePass, DistributeLoot, …) via an
     7→ * abstract “BlockchainPort”.  The class takes care of
     8→ *   • provider / signer boot-strapping
     9→ *   • safe gas-estimation & automatic gas-margin padding
    10→ *   • common transaction life-cycle helpers (waitForTx, getReceipt, …)
    11→ *   • minimal proxy-deployment helper for upgradeable contracts
    12→ *   • typed contract factory / loader
    13→ *   • basic event-listening utilities
    14→ *
    15→ * NOTE: All domain logic is intentionally kept out of this file – this is *purely* an
    16→ *       infrastructure concern in accordance with Clean Architecture guidelines.
    17→ ******************************************************************************************/
    18→
    19→import * as dotenv from 'dotenv';
    20→import { ethers, providers, Wallet, Contract, ContractFactory, BigNumberish } from 'ethers';
    21→import { Typed } from '@ethersproject/abi'; // handy helper for typed event args (optional)
    22→import assert from 'assert';
    23→
    24→dotenv.config();
    25→
    26→/* -------------------------------------------------------------------------- */
    27→/*                                 Interfaces                                 */
    28→/* -------------------------------------------------------------------------- */
    29→
    30→export interface ContractArtifact {
    31→    abi: any;
    32→    bytecode: string;
    33→    /* Optional:  metadata / source map, etc. are ignored by this adapter   */
    34→}
    35→
    36→export interface EthersServiceOptions {
    37→    rpcUrl: string;
    38→    privateKey: string;
    39→    chainId: number;
    40→    defaultConfirmations: number;
    41→    gasLimitBuffer: number;   // e.g. 1.2 => +20 %
    42→    gasPriceMultiplier: number;
    43→}
    44→
    45→/**
    46→ * Interface describing the publicly consumed surface of the service.
    47→ * (“BlockchainPort” in domain language)
    48→ */
    49→export interface IEthersService {
    50→    getProvider(): providers.Provider;
    51→    getSigner(): Wallet;
    52→
    53→    loadContract<T extends Contract = Contract>(
    54→        address: string,
    55→        abi: any,
    56→        signerOrProvider?: Wallet | providers.Provider
    57→    ): T;
    58→
    59→    deployProxy(
    60→        implementationArtifact: ContractArtifact,
    61→        initializeArgs?: readonly any[]
    62→    ): Promise<Contract>;
    63→
    64→    sendTransaction(
    65→        tx: providers.TransactionRequest,
    66→        confirmations?: number
    67→    ): Promise<providers.TransactionReceipt>;
    68→
    69→    waitForTx(
    70→        txHash: string,
    71→        confirmations?: number
