    73→
    74→    estimateGas(tx: providers.TransactionRequest): Promise<ethers.BigNumber>;
    75→
    76→    on<E extends readonly unknown[]>(
    77→        contract: Contract,
    78→        event: string,
    79→        cb: (...args: E) => void
    80→    ): void;
    81→
    82→    removeListener(
    83→        contract: Contract,
    84→        event: string,
    85→        cb: (...args: any[]) => void
    86→    ): void;
    87→}
    88→
    89→/* -------------------------------------------------------------------------- */
    90→/*                                  Service                                   */
    91→/* -------------------------------------------------------------------------- */
    92→
    93→export class EthersService implements IEthersService {
    94→    /* Singleton holder – prevents multiple providers in serverless contexts */
    95→    private static _instance: EthersService;
    96→
    97→    public static get instance(): EthersService {
    98→        if (!EthersService._instance) {
    99→            EthersService._instance = new EthersService();
   100→        }
   101→        return EthersService._instance;
   102→    }
   103→
   104→    /* ---------------------------------------------------------------------- */
   105→
   106→    private readonly provider: providers.JsonRpcProvider;
   107→    private readonly signer: Wallet;
   108→    private readonly options: EthersServiceOptions;
   109→
   110→    private constructor(customOptions?: Partial<EthersServiceOptions>) {
   111→        /* 1️⃣  Assemble effective options (env ▶ default ▶ overrides) */
   112→        const defaults: EthersServiceOptions = {
   113→            rpcUrl: process.env.BLOCKCHAIN_RPC_URL || 'http://127.0.0.1:8545',
   114→            privateKey: process.env.BLOCKCHAIN_PRIVATE_KEY || '',
   115→            chainId: +(process.env.BLOCKCHAIN_CHAIN_ID || 1337),
   116→            defaultConfirmations: parseInt(process.env.BLOCKCHAIN_CONFIRMATIONS || '1', 10),
   117→            gasLimitBuffer: 1.2,
   118→            gasPriceMultiplier: 1.1
   119→        };
   120→        this.options = { ...defaults, ...(customOptions || {}) };
   121→
   122→        /* 2️⃣  Provider / signer boot-strap with runtime validations          */
   123→        assert.ok(this.options.privateKey, 'Missing private key for signer');
   124→        this.provider = new ethers.providers.JsonRpcProvider(
   125→            this.options.rpcUrl,
   126→            this.options.chainId
