   130→
   131→    /* ---------------------------------------------------------------------- */
   132→    /*                                Getters                                 */
   133→    /* ---------------------------------------------------------------------- */
   134→
   135→    public getProvider(): providers.Provider {
   136→        return this.provider;
   137→    }
