   141→    }
   142→
   143→    /* ---------------------------------------------------------------------- */
   144→    /*                              Tx helpers                                */
   145→    /* ---------------------------------------------------------------------- */
   146→
   147→    /**
   148→     * Estimate gas, apply buffer, fetch gasPrice (EIP-1559 aware), then sign+send
   149→     */
   150→    public async sendTransaction(
   151→        tx: providers.TransactionRequest,
   152→        confirmations = this.options.defaultConfirmations
   153→    ): Promise<providers.TransactionReceipt> {
   154→        const populated: providers.TransactionRequest = await this.populateTx(tx);
   155→        const response = await this.signer.sendTransaction(populated);
   156→        return await response.wait(confirmations);
   157→    }
   158→
   159→    /**
   160→     * Wait for an already-submitted tx-hash
   161→     */
   162→    public async waitForTx(txHash: string, confirmations = this.options.defaultConfirmations) {
   163→        return await this.provider.waitForTransaction(txHash, confirmations);
   164→    }
   165→
   166→    /**
   167→     * Populates missing transaction parameters (gas, gasPrice, nonce, …)
   168→     */
   169→    private async populateTx(
   170→        tx: providers.TransactionRequest
   171→    ): Promise<providers.TransactionRequest> {
   172→        // gas limit
   173→        if (!tx.gasLimit) {
   174→            const est = await this.estimateGas(tx);
   175→            tx.gasLimit = est;
   176→        }
   177→
   178→        // gasPrice or EIP-1559 fees
   179→        if (!tx.gasPrice && (!tx.maxFeePerGas || !tx.maxPriorityFeePerGas)) {
   180→            const feeData = await this.provider.getFeeData();
   181→            if (feeData.maxFeePerGas && feeData.maxPriorityFeePerGas) {
   182→                // Prefer EIP-1559 when available
   183→                tx.maxFeePerGas = feeData.maxFeePerGas
   184→                    .mul(Math.round(this.options.gasPriceMultiplier * 100))
   185→                    .div(100);
   186→                tx.maxPriorityFeePerGas = feeData.maxPriorityFeePerGas
   187→                    .mul(Math.round(this.options.gasPriceMultiplier * 100))
   188→                    .div(100);
   189→            } else if (feeData.gasPrice) {
   190→                tx.gasPrice = feeData.gasPrice
   191→                    .mul(Math.round(this.options.gasPriceMultiplier * 100))
   192→                    .div(100);
   193→            }
   194→        }
   195→
   196→        // chainId, nonce
   197→        tx.chainId = tx.chainId ?? this.options.chainId;
   198→        tx.nonce = tx.nonce ?? (await this.signer.getTransactionCount('pending'));
