   200→        return tx;
   201→    }
   202→
   203→    /**
   204→     * Estimate gas w/ buffer to reduce out-of‐gas (defaults to +20 %)
   205→     */
   206→    public async estimateGas(
   207→        tx: providers.TransactionRequest | Contract
   208→    ): Promise<ethers.BigNumber> {
   209→        let estimate: ethers.BigNumber;
   210→        if (tx instanceof Contract) {
   211→            throw new Error('Cannot estimate gas for raw contract; call method estimateGas.*');
   212→        } else {
   213→            estimate = await this.provider.estimateGas(tx);
   214→        }
   215→
   216→        return estimate
   217→            .mul(Math.round(this.options.gasLimitBuffer * 100))
   218→            .div(100);
