   265→        );
   266→
   267→        const proxyFactory = new ContractFactory(PROXY_ABI, PROXY_BYTECODE, this.signer);
   268→
   269→        const proxy = await proxyFactory.deploy(
   270→            implContract.address,
   271→            this.signer.address,
