     2→/****************************************************************************************
     3→ * StellarStage Carnival (backend)
     4→ * File:    packages/backend/src/infrastructure/adapters/blockchain/contract.mapper.ts
     5→ * Author:  StellerStage Core Team
     6→ *
     7→ * Purpose:
     8→ *   Bridges domain-layer entities/event objects with low-level EVM smart–contract calls.
     9→ *   All “knowledge” about on-chain ABI encodings, contract addresses and network IDs
    10→ *   lives here, keeping the rest of the codebase completely blockchain-agnostic.
    11→ *
    12→ *   – Maps domain commands to contract write-transactions (mint, stake, distribute…)
    13→ *   – Hydrates ethers.js Contract instances from a runtime registry
    14→ *   – Translates on-chain events back into strongly-typed domain events
    15→ *
    16→ * Usage example (inside a Use-Case service):
    17→ *   const { contract, data } = contractMapper.toMintShowPassTx(pass);
    18→ *   const tx = await signer.sendTransaction({ ...data, to: contract.address });
    19→ *
    20→ ****************************************************************************************/
    21→
    22→import { ethers, Contract, ContractInterface, Event } from 'ethers';
    23→import path from 'path';
    24→import fs from 'fs';
    25→import { z } from 'zod';
    26→
    27→import { ShowPass } from '../../../domain/entities/ShowPass';
    28→import { Loot } from '../../../domain/entities/Loot';
    29→import { LiveVoteCast } from '../../../domain/events/LiveVoteCast';
    30→import { DomainEvent } from '../../../domain/events/DomainEvent';
    31→
    32→import { BlockchainConfig, NetworkId } from '../config/blockchain.config';
    33→import logger from '../../logger';
    34→import { InfrastructureError } from '../../errors';
    35→
    36→/**
    37→ * Type guards & runtime validators (zod) — make absolutely sure we’re never sending
    38→ * malformed data to the chain. These schemas travel with compiled JS (no TS only).
    39→ */
    40→const MintPassParamsSchema = z.object({
    41→  to: z.string().startsWith('0x').length(42),
    42→  tokenId: z.bigint().nonnegative(),
    43→  metadataURI: z.string().url(),
    44→});
    45→
    46→export type MintPassParams = z.infer<typeof MintPassParamsSchema>;
    47→
    48→/**
    49→ * Minimal subset of contract ABI fragments we care about for mappings
    50→ * (we don’t want to load the entire, heavyweight ABI if not needed).
    51→ */
    52→const ABI_FRAGMENT: Record<
    53→  'ShowPass' | 'Loot' | 'Governance',
    54→  ContractInterface
    55→> = {
    56→  ShowPass: [
    57→    'function safeMint(address to, uint256 tokenId, string memory uri) public',
    58→    'event Transfer(address indexed from, address indexed to, uint256 indexed tokenId)',
    59→  ],
    60→  Loot: [
    61→    'function distribute(address to, uint256 lootId, uint256 qty) external',
    62→    'event LootDistributed(address indexed to, uint256 indexed lootId, uint256 qty)',
    63→  ],
    64→  Governance: [
    65→    'function castVote(uint256 proposalId, uint8 option) external',
    66→    'event VoteCast(address voter, uint256 indexed proposalId, uint8 option)',
    67→  ],
    68→};
    69→
    70→/**
    71→ * Simple, in-memory contract registry built from BlockchainConfig.
    72→ * Could be easily replaced with a dynamic (e.g., ENS) lookup later.
    73→ */
    74→class ContractRegistry {
    75→  private readonly registry: Map<
    76→    NetworkId,
    77→    Record<'ShowPass' | 'Loot' | 'Governance', string>
    78→  > = new Map();
    79→
    80→  constructor(private readonly cfg: BlockchainConfig) {
    81→    this.bootstrap(cfg);
    82→  }
    83→
    84→  getAddress(
    85→    network: NetworkId,
    86→    contractType: 'ShowPass' | 'Loot' | 'Governance',
    87→  ): string {
    88→    const map = this.registry.get(network);
    89→    if (!map || !map[contractType]) {
    90→      throw new InfrastructureError(
    91→        `Unknown contract address for ${contractType} on ${network}`,
    92→      );
    93→    }
    94→    return map[contractType];
    95→  }
    96→
    97→  private bootstrap(cfg: BlockchainConfig): void {
    98→    Object.entries(cfg.contracts).forEach(([network, contracts]) => {
    99→      this.registry.set(network as NetworkId, contracts);
   100→    });
   101→  }
   102→}
   103→
   104→/**
   105→ * Main mapper — all mapping logic lives here, centralising blockchain concerns.
   106→ */
   107→export class ContractMapper {
   108→  private readonly provider: ethers.JsonRpcProvider;
   109→  private readonly registry: ContractRegistry;
   110→
   111→  constructor(private readonly cfg: BlockchainConfig) {
   112→    this.provider = new ethers.JsonRpcProvider(cfg.rpcUrl);
   113→    this.registry = new ContractRegistry(cfg);
   114→  }
   115→
   116→  /**************************************************************************
   117→   *                               WRITES                                  *
   118→   **************************************************************************/
   119→
   120→  /**
   121→   * Translates domain ShowPass entity to low-level tx data for safeMint().
   122→   * Returns the prepared Contract instance as well so caller can easily
   123→   * connect a signer and send the transaction.
   124→   */
   125→  public toMintShowPassTx(
   126→    pass: ShowPass,
   127→  ): { contract: Contract; data: ethers.TransactionRequest } {
   128→    // Build and validate params
   129→    const params: MintPassParams = {
   130→      to: pass.ownerAddress,
   131→      tokenId: BigInt(pass.id),
   132→      metadataURI: pass.metadataURI,
   133→    };
   134→    MintPassParamsSchema.parse(params);
   135→
   136→    const contract = this.getContract('ShowPass');
   137→    const data = contract.interface.encodeFunctionData('safeMint', [
   138→      params.to,
   139→      params.tokenId,
   140→      params.metadataURI,
   141→    ]);
   142→
   143→    return {
   144→      contract,
   145→      data: {
   146→        to: contract.address,
   147→        data,
   148→        // gasLimit/gasPrice left undefined; caller (service) or wallet picks values.
   149→      },
   150→    };
   151→  }
   152→
   153→  public toDistributeLootTx(
   154→    loot: Loot,
   155→    recipient: string,
   156→  ): { contract: Contract; data: ethers.TransactionRequest } {
   157→    if (!ethers.isAddress(recipient))
   158→      throw new InfrastructureError('Recipient must be a valid EVM address');
   159→
   160→    const contract = this.getContract('Loot');
   161→    const encoded = contract.interface.encodeFunctionData('distribute', [
   162→      recipient,
   163→      loot.id,
   164→      loot.quantity,
   165→    ]);
   166→
   167→    return {
   168→      contract,
   169→      data: {
   170→        to: contract.address,
   171→        data: encoded,
   172→      },
   173→    };
   174→  }
   175→
   176→  /**************************************************************************
   177→   *                               READS                                   *
   178→   **************************************************************************/
   179→
   180→  /**
   181→   * Parses raw on-chain Event object into strongly typed domain event.
   182→   * Add new pattern matches here whenever a new event is added on-chain.
   183→   */
   184→  public toDomainEvent(event: Event): DomainEvent | null {
   185→    const { fragment } = event;
   186→    try {
   187→      switch (fragment?.name) {
   188→        case 'Transfer': {
   189→          // Transfer event is used to mint as well (from = 0x0)
   190→          const [from, to, tokenId] = event.args as [string, string, bigint];
   191→          return new LiveVoteCast(
   192→            'passTransfer',
   193→            {
   194→              from,
   195→              to,
   196→              tokenId: Number(tokenId),
   197→            },
   198→            event.blockNumber,
   199→          );
   200→        }
   201→
   202→        case 'LootDistributed': {
   203→          const [to, lootId, qty] = event.args as [string, bigint, bigint];
   204→          return {
   205→            type: 'LootDistributed',
   206→            payload: {
   207→              to,
   208→              lootId: Number(lootId),
   209→              qty: Number(qty),
   210→            },
   211→            occurredAtBlock: event.blockNumber,
   212→          } as DomainEvent;
   213→        }
   214→
   215→        case 'VoteCast': {
   216→          const [voter, proposalId, option] = event.args as [
   217→            string,
   218→            bigint,
   219→            number,
   220→          ];
   221→          return new LiveVoteCast(
   222→            'governanceVote',
   223→            {
   224→              voter,
   225→              proposalId: Number(proposalId),
   226→              option,
   227→            },
   228→            event.blockNumber,
   229→          );
   230→        }
   231→
   232→        default:
   233→          return null; // Unrecognised event; ignore
   234→      }
   235→    } catch (err) {
   236→      // Never let an event crash the stream; just log & skip
   237→      logger.warn(
   238→        { err, txHash: event.transactionHash, event: fragment?.name },
   239→        'Failed to map blockchain event',
   240→      );
   241→      return null;
   242→    }
   243→  }
   244→
   245→  /**************************************************************************
   246→   *                             INTERNAL                                  *
   247→   **************************************************************************/
   248→
   249→  /**
   250→   * Resolves a Contract connected to read-only provider.
   251→   * (Use contract.connect(signer) before doing writes.)
   252→   */
   253→  private getContract(
   254→    type: 'ShowPass' | 'Loot' | 'Governance',
   255→  ): ethers.Contract {
   256→    const address = this.registry.getAddress(this.cfg.networkId, type);
   257→    const abi = ABI_FRAGMENT[type];
   258→
   259→    return new ethers.Contract(address, abi, this.provider);
   260→  }
   261→}
   262→
   263→/******************************************************************************
   264→ *                                TYPES & EXPORTS                             *
   265→ ******************************************************************************/
   266→
   267→export default ContractMapper;
   268→
   269→/******************************************************************************
   270→ *                                   EOF                                      *
   271→ ******************************************************************************/
   272→```

