     2→/****************************************************************************************
     3→ * File: packages/backend/src/application/observers/stage-event.observer.ts
     4→ * Project: StellarStage Carnival ⭑ Interactive NFT Showrunner
     5→ *
     6→ * Description:
     7→ *   Listens to high-level StageDomainEvents fired from the core domain layer and
     8→ *   broadcasts them to external delivery mechanisms (WebSockets, GraphQL
     9→ *   subscriptions, Push notifications, etc.). The observer lives in the
    10→ *   “application” layer (Clean Architecture) and therefore:
    11→ *
    12→ *     • Depends only on abstractions (EventBus, RealtimeGateway, LoggerPort, …)
    13→ *     • Translates domain-centric data into DTOs optimised for front-end clients
    14→ *     • Calls application-level use-cases when cascading workflows are needed
    15→ *
    16→ *   The observer is registered once at application bootstrap.
    17→ ****************************************************************************************/
    18→
    19→import { injectable, inject } from 'tsyringe';
    20→
    21→import type { DomainEvent } from '../../domain/events/domain-event.interface';
    22→import { ActStartedEvent } from '../../domain/events/act-started.event';
    23→import { ActEndedEvent } from '../../domain/events/act-ended.event';
    24→import { VoteCastEvent } from '../../domain/events/vote-cast.event';
    25→import { LootDistributedEvent } from '../../domain/events/loot-distributed.event';
    26→import { PassStakedEvent } from '../../domain/events/pass-staked.event';
    27→
    28→import type { EventObserver } from '../ports/event-observer.port';
    29→import type { EventBus } from '../ports/event-bus.port';
    30→import type { RealtimeGateway } from '../ports/realtime-gateway.port';
    31→import type { LoggerPort } from '../ports/logger.port';
    32→import { MINT_LOOT_ON_ACT_END } from '../config/constants';
    33→
    34→@injectable()
    35→export class StageEventObserver implements EventObserver {
    36→  constructor(
    37→    @inject('EventBus') private readonly eventBus: EventBus,
    38→    @inject('RealtimeGateway') private readonly realtime: RealtimeGateway,
    39→    @inject('Logger') private readonly logger: LoggerPort
    40→  ) {
    41→    this.register();
    42→  }
    43→
    44→  /*****************************************************************************
    45→   * Public API
    46→   ****************************************************************************/
    47→
    48→  /**
    49→   * on
    50→   * ----
    51→   * The single entry-point required by the EventObserver interface.
    52→   */
    53→  async on(event: DomainEvent): Promise<void> {
    54→    // Every handler runs in its own try/catch block
    55→    // so one failure does not break other observers.
    56→    try {
    57→      switch (event.constructor) {
    58→        case ActStartedEvent:
    59→          await this.handleActStarted(event as ActStartedEvent);
    60→          break;
    61→
    62→        case ActEndedEvent:
    63→          await this.handleActEnded(event as ActEndedEvent);
    64→          break;
    65→
    66→        case VoteCastEvent:
    67→          await this.handleVoteCast(event as VoteCastEvent);
    68→          break;
    69→
    70→        case LootDistributedEvent:
    71→          await this.handleLootDistributed(event as LootDistributedEvent);
    72→          break;
    73→
    74→        case PassStakedEvent:
    75→          await this.handlePassStaked(event as PassStakedEvent);
    76→          break;
    77→
    78→        default:
    79→          // Unknown or unhandled event – just ignore for now.
    80→          this.logger.debug(
    81→            `[StageEventObserver] Ignored event "${event.name}" (${event.id})`
    82→          );
    83→      }
    84→    } catch (err) {
    85→      this.logger.error(
    86→        `[StageEventObserver] Failed while processing ${event.name}: ${err}`,
    87→        err as Error
    88→      );
    89→    }
    90→  }
    91→
    92→  /*****************************************************************************
    93→   * Private helpers
    94→   ****************************************************************************/
    95→
    96→  private register(): void {
    97→    this.eventBus.subscribe(this);
    98→    this.logger.info('[StageEventObserver] Registered with EventBus');
    99→  }
   100→
   101→  /**
   102→   * handleActStarted
   103→   * ----------------
   104→   * Broadcasts “actStarted” payloads to every connected stage channel.
   105→   */
   106→  private async handleActStarted(event: ActStartedEvent): Promise<void> {
   107→    const payload = {
   108→      actId: event.actId.value,
   109→      showId: event.showId.value,
   110→      startsAt: event.startedAt.toISOString(),
   111→      metadata: event.metadata
   112→    };
   113→
   114→    await this.realtime.broadcast({
   115→      channel: `show:${payload.showId}`,
   116→      event: 'actStarted',
   117→      payload
   118→    });
   119→
   120→    this.logger.info(
   121→      `[StageEventObserver] Act "${payload.actId}" started – broadcasted`
   122→    );
   123→  }
   124→
   125→  /**
   126→   * handleActEnded
   127→   * --------------
   128→   * When an act ends we optionally trigger on-chain loot minting in
   129→   * addition to pushing the event downstream.
   130→   */
   131→  private async handleActEnded(event: ActEndedEvent): Promise<void> {
   132→    const payload = {
   133→      actId: event.actId.value,
   134→      showId: event.showId.value,
   135→      endedAt: event.endedAt.toISOString()
   136→    };
   137→
   138→    await this.realtime.broadcast({
   139→      channel: `show:${payload.showId}`,
   140→      event: 'actEnded',
   141→      payload
   142→    });
   143→
   144→    this.logger.info(
   145→      `[StageEventObserver] Act "${payload.actId}" ended – broadcasted`
   146→    );
   147→
   148→    if (MINT_LOOT_ON_ACT_END) {
   149→      await this.eventBus.publish(
   150→        new LootDistributedEvent(
   151→          event.showId,
   152→          event.actId,
   153→          /* synthetic loot-drop id */ undefined
   154→        )
   155→      );
   156→      this.logger.debug(
   157→        `[StageEventObserver] Triggered LootDistributedEvent for act ${payload.actId}`
   158→      );
   159→    }
   160→  }
   161→
   162→  /**
   163→   * handleVoteCast
   164→   * --------------
   165→   * Pushes real-time vote tallies so the front-end can display live results.
   166→   */
   167→  private async handleVoteCast(event: VoteCastEvent): Promise<void> {
   168→    const payload = {
   169→      voter: event.walletAddress.toChecksumAddress(),
   170→      proposalId: event.proposalId.value,
   171→      choice: event.choice,
   172→      weight: event.weight.toString()
   173→    };
   174→
   175→    await this.realtime.broadcast({
   176→      channel: `proposal:${payload.proposalId}`,
   177→      event: 'voteCast',
   178→      payload
   179→    });
   180→
   181→    this.logger.debug(
   182→      `[StageEventObserver] Vote received for proposal "${payload.proposalId}"`
   183→    );
   184→  }
   185→
   186→  /**
   187→   * handleLootDistributed
   188→   * ---------------------
   189→   * After loot drops we update audiences so their wallets refresh metadata.
   190→   */
   191→  private async handleLootDistributed(
   192→    event: LootDistributedEvent
   193→  ): Promise<void> {
   194→    const payload = {
   195→      dropId: event.dropId.value,
   196→      showId: event.showId.value,
   197→      actId: event.actId?.value,
   198→      totalItems: event.totalItems
   199→    };
   200→
   201→    await this.realtime.broadcast({
   202→      channel: `show:${payload.showId}`,
   203→      event: 'lootDistributed',
   204→      payload
   205→    });
   206→
   207→    this.logger.info(
   208→      `[StageEventObserver] Loot drop "${payload.dropId}" sent to show ${payload.showId}`
   209→    );
   210→  }
   211→
   212→  /**
   213→   * handlePassStaked
   214→   * ----------------
   215→   * Notifies governance dashboards of stake changes.
   216→   */
   217→  private async handlePassStaked(event: PassStakedEvent): Promise<void> {
   218→    const payload = {
   219→      passTokenId: event.passTokenId.value,
   220→      wallet: event.staker.toChecksumAddress(),
   221→      stakedAt: event.stakedAt.toISOString()
   222→    };
   223→
   224→    await this.realtime.broadcast({
   225→      channel: `wallet:${payload.wallet}`,
   226→      event: 'passStaked',
   227→      payload
   228→    });
   229→
   230→    this.logger.debug(
   231→      `[StageEventObserver] Pass ${payload.passTokenId} staked by ${payload.wallet}`
   232→    );
   233→  }
   234→}
   235→
   236→/****************************************************************************************
   237→ * Bootstrap helper
   238→ * ----------------
   239→ * Called from the application’s IoC root.  Keeps wiring separate from the class
   240→ * definition, allowing the observer to be tree-shaken when unused (e.g. tests).
   241→ ****************************************************************************************/
   242→
   243→/**
   244→ * registerStageEventObserver
   245→ * --------------------------
   246→ * Attaches the observer to the EventBus through the dependency container.
   247→ */
   248→export const registerStageEventObserver = (): void => {
   249→  // The container will resolve dependencies declared in the constructor.
   250→  // eslint-disable-next-line @typescript-eslint/no-var-requires
   251→  const { container } = require('tsyringe');
   252→  container.resolve(StageEventObserver);
   253→};
